[FormControlEventHandler(formControlStr(SalesEditLines, ETG_BLnumber), FormControlEventType::Lookup)]
public static void ETG_BLnumber_OnLookup(FormControl sender, FormControlEventArgs e)
{

    Query                   query = new Query();
    QueryBuildDataSource    qbd,qbd1, qbd2;
    SysTableLookup          sysTableLookup;
    QueryBuildRange         qbr,qbr1;
    SalesId                 salesId, documentStatus ;
    PackingSlipId           packingSlipId;
    salesId         = sender.formRun().design().controlName(formControlStr(SalesEditLines, SalesParmTable_SalesId)).valueStr();
    documentStatus  = sender.formRun().design().controlName(formControlStr(SalesEditLines, SalesParmTable_Ordering)).valueStr();

    if (documentStatus   == enum2Str(DocumentStatus::Invoice))
    {
        sysTableLookup = SysTableLookup::newParameters(tableNum(ETG_BillOfLading), sender);

        qbd = query.addDataSource(tableNum(ETG_BillOfLading));
        qbr = qbd.addRange(fieldnum(ETG_BillOfLading, SalesId)) ;
        qbr.value(salesId) ;
        qbr = qbd.addRange(fieldnum(ETG_BillOfLading, InvoiceId)) ;
        qbr.value('" "') ;

        sysTableLookup.addLookupField(fieldNum(ETG_BillOfLading, BOLNo));
        sysTableLookup.addLookupField(fieldNum(ETG_BillOfLading, packingSlipId ));
        sysTableLookup.addLookupField(fieldNum(ETG_BillOfLading, SalesId));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
    }
}

[FormControlEventHandler(formControlStr(vendeditinvoice, ETG_BLnumber), FormControlEventType::Lookup)]
public static void ETG_BLnumberVend_OnLookup(FormControl sender, FormControlEventArgs e)
{

    Query                   query = new Query();
    QueryBuildDataSource    qbd,qbd1, qbd2;
    SysTableLookup          sysTableLookup;
    QueryBuildRange         qbr,qbr1;
    PurchId                 purchId;

    purchId         = sender.formRun().design().controlName(formControlStr(vendeditinvoice, PurchParmTable_PurchId)).valueStr();

    sysTableLookup = SysTableLookup::newParameters(tableNum(VendPackingSlipTrans), sender);
    qbd = query.addDataSource(tableNum(VendPackingSlipTrans));
    qbr = qbd.addRange(fieldnum(VendPackingSlipTrans,OrigPurchid)) ;
    qbr.value(purchId) ;

    qbr = qbd.addRange(fieldnum(VendPackingSlipTrans,BOLNo)) ;
    qbr.value('!" "') ;

    qbd1=qbd.addDataSource(tableNum(vendInvoicePackingSlipQuantityMatch));
    qbd1.addLink(fieldNum(VendPackingSlipTrans,SourceDocumentLine),fieldNum(vendInvoicePackingSlipQuantityMatch,PackingSlipSourceDocumentLine));
    qbd1.relations(true);
    qbd1.joinMode(JoinMode::NoExistsJoin);

    sysTableLookup.addLookupField(fieldNum(VendPackingSlipTrans, BOLNo));
    sysTableLookup.addLookupField(fieldNum(VendPackingSlipTrans, packingSlipId ));
    sysTableLookup.addLookupField(fieldNum(VendPackingSlipTrans, BOLDate ));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();

}
